#ifdef __APPLE__
    #define GL_SILENCE_DEPRECATION
    #include <GLUT/glut.h>
#else
    #include <GL/glut.h>
#endif

#include <cmath>
#include <iostream>

void MidPointline(int x1, int y1, int x2, int y2) {
    int dx = std::abs(x2 - x1);
    int dy = std::abs(y2 - y1);
    int sx = (x1 < x2) ? 1 : -1;
    int sy = (y1 < y2) ? 1 : -1;

    int x = x1;
    int y = y1;

    glBegin(GL_POINTS);
    if (dx >= dy) { 
        int d = dx - 2 * dy;   
        int dt = 2 * dx - 2 * dy; 
        int db = - 2 * dy;      
        for (int i = 0; i <= dx; i++) {
            glVertex2i(x, y);
            if (d < 0) {  
                x += sx;      
                y += sy;        
                d += dt;        
            } else {
                x += sx;   
                d += db;        
            }
        }
    } 
    else { 
        int d = dy - 2 * dx;    // dx和dy互换即可
        int dt = 2 * dy - 2 * dx;
        int db = - 2 * dx;
        for (int i = 0; i <= dy; i++) {
            glVertex2i(x, y);
            if (d < 0) {
                y += sy;
                x += sx;
                d += dt;
            } else {
                y += sy;
                d += db;
            }
        }
    }
    glEnd();
}

void init(void) {
    glClearColor(1.0, 1.0, 0.0, 1.0);
    glMatrixMode(GL_PROJECTION);
    glLoadIdentity();
    gluOrtho2D(0.0, 600.0, 400.0, 0.0);
}

void myDisplay(void) {
    glClear(GL_COLOR_BUFFER_BIT);
    glColor3f(1.0f, 0.0f, 0.0f);
    glPointSize(5); 
    MidPointline(50, 50, 300, 60);    
    MidPointline(300, 60, 200, 200);  
    MidPointline(200, 200, 50, 50);   
    glFlush();
    glutSwapBuffers();
}

int main(int argc, char* argv[]) {
    glutInit(&argc, argv);
    glutInitDisplayMode(GLUT_RGB | GLUT_DOUBLE);
    glutInitWindowPosition(50, 50);
    glutInitWindowSize(600, 400);
    glutCreateWindow("l2");
    init(); 
    glutDisplayFunc(myDisplay);
    glutMainLoop();
    return 0;
}

